import React, { useEffect, useState } from "react";
import { Link, useNavigate } from 'react-router-dom';
import alertPopUp from 'sweetalert2';
import withReactContent from 'sweetalert2-react-content';
import { deleteModalSwal, epochTogmt, errorMessagePopUp } from "src/utils/Common";
import { CButton } from "@coreui/react";
import { deleteCategory, fetchAllCategory } from "src/components/services/CategoryApi";
import DataTable from "react-data-table-component";
import { customStyles } from "../../utils/tableCustomStyles";
import { tableCategoryConstant } from "./tableCategoryConstant";
import authService from "src/auth/auth.service";

const MySwal = withReactContent(alertPopUp);

const CategoryList = () => {
    const [rowData, setRowData] = useState([]);
    const navigate = useNavigate();

    useEffect(() => {
        fetchCategoryList();
    }, []);

    const handleDelete = async (id) => {
        const response = await deleteCategory(id);
        if (response?.code === 200) {
            fetchCategoryList();
        }
        if (response?.code === 409) {
            errorMessagePopUp(response?.message);
        }
    }

    const fetchCategoryList = async () => {
        const response = await fetchAllCategory(1, 30);
        if(response?.code === 200) {
            setRowData(response?.results);   
        }
    };

    const handleConfirmModal = (id) => {
        const handleConfirm = async () => {
            const swalval = await MySwal.fire(deleteModalSwal);
            if (swalval && swalval.value === true) {
                handleDelete(id)
            }
        };
        handleConfirm();
    };

    return (<div className='row'>
        <div className="col2Large">
            <DataTable
                title="Category"
                columns={tableCategoryConstant(fetchCategoryList, handleConfirmModal)}
                data={rowData}
                customStyles={customStyles}
                //actions={this.actionButton()}
                pagination
                paginationPerPage={10}
                pointerOnHover
                fixedHeader
                noContextMenu
                fixedHeaderScrollHeight={"calc(100vh - 226px)"}
            />
        </div>
       {authService.getPermission("CATEGORY_CREATE") && <div className='col-sm-12'>
            <Link to={"/category/create"}>
                <CButton type="submit" color="primary" className="create-btn" style={{ float: "right" }}>
                    {"+ Create Category"}
                </CButton>
            </Link>
        </div>}
    </div>)
}

export default CategoryList;
